Recipe.create!([
  {name: "Cannabutter", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">1 cup unsalted butter (2 sticks)</li>\r\n\t<li class=\"list-group-item\">&frac12; cup water (add more water at any time if needed)</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">7</span> ground&nbsp;weed</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong> Add &frac12; cup of water and 2 sticks (&frac12; lb) of butter in a saucepan and bring to a simmer on low to medium heat. Adding water helps to regulate the temperature and prevents the butter from scorching. As butter begins to melt, add in ground weed.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong> Maintain low heat and let the mixture simmer for 2-3 hours, stirring occasionally. Make sure the mixture never comes to a full boil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong> Pour the hot mixture into a glass container, using a cheesecloth to strain out all ground weed from the butter mixture. Squeeze or press the plant material to get as much liquid out of the weed as possible. Discard leftover weed.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong> Cover and refrigerate remaining liquid overnight or until the butter is fully hardened. Once hardened, the butter will separate from the water, allowing you to lift the cannabutter out of the container. Discard remaining water after removing the hardened cannabutter.</li>\r\n\t<li class=\"list-group-item\"><strong>The cannabutter in the container should have a slightly green tinge from the cannabis. Now you are ready to make some cannabis-infused meals!</strong></li>\r\n</ul>\r\n\r\n", suggested_quantity: 7.0, suggested_portion: 48.0, video: "https://www.youtube.com/embed/hxUbe0GeL_k", slug: "cannabutter", category_id: 2, photo_file_name: "cannabutter.jpg", photo_content_type: "image/jpeg", photo_file_size: 6724, photo_updated_at: "2018-06-05 23:50:59", description: "Deliciously creamy real-dairy cannabutter. Can be used for any recipe.", position: 1},
  {name: "Whiskey", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">750 ml bottle of bourbon whiskey</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">7 g</span> ground weed</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1:</strong> Pour the bottle of whiskey into a sealable jar (or pour out a little bit of whiskey to make up for the added volume of the weed) and add the ground weed.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2:</strong> Shake the bottle and let it sit, out of the sun, for at least 48 hours. Shake it up at least once a day until it has reached your desired potency - up to one month if possible. The longer it sits, the more potent it will be.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3:</strong> Pour the whiskey mixture into a glass container, using a cheesecloth to strain out all ground weed from the whiskey. Repeat this step as necessary to strain all of the whiskey from the ground weed, and discard the remaining weed.</li>\r\n</ul>\r\n", suggested_quantity: 7.0, suggested_portion: 20.0, video: "https://www.youtube.com/embed/w3QapjNxqos", slug: "whiskey", category_id: 4, photo_file_name: "whiskey-(1).jpg", photo_content_type: "image/jpeg", photo_file_size: 12393, photo_updated_at: "2018-06-05 23:50:03", description: "Explore the flavour of the best whiskies with the glorious cannabis aroma.", position: 8},
  {name: "Pot Cookies", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">1/2 cup cannabutter with <span id=\"grams-quantity-recipe\">3.5 grams</span>&nbsp;weed - <a class=\"recipe-reference\" href=\"http://www.howtoedibles.com/recipes/cannabutter\" target=\"_blank\">See the recipe</a></li>\r\n\t<li class=\"list-group-item\">1/2 cup granulated sugar</li>\r\n\t<li class=\"list-group-item\">1/4 cup brown sugar</li>\r\n\t<li class=\"list-group-item\">2 teaspoons vanilla extract</li>\r\n\t<li class=\"list-group-item\">1 large egg</li>\r\n\t<li class=\"list-group-item\">1 3/4 cups all-purpose flour</li>\r\n\t<li class=\"list-group-item\">1/2 teaspoon baking soda</li>\r\n\t<li class=\"list-group-item\">pinch of salt</li>\r\n\t<li class=\"list-group-item\">1 cup chocolate chips</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Preheat the oven to 350 F..</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Microwave the cannabutter for about 40 seconds. Butter should be completely melted but shouldn&#39;t be hot.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>In a large bowl, mix cannabutter with the sugars until well-combined.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Stir in vanilla and egg until incorporated.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Add the flour, baking soda, and salt. Please read the recipe note about properly measuring flour.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Mix dough until just combined. Dough should be soft and a little sticky but not overly sticky.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Stir in chocolate chips.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Scoop out 1.5 tablespoons of dough (medium cookie scoop) and place 2 inches apart on baking sheet.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Bake for 7-10 minutes, or until cookies are set. They will be puffy and still look a little underbaked in the middle.</li>\r\n</ul>\r\n", suggested_quantity: 3.5, suggested_portion: 24.0, video: "", slug: "pot-cookies", category_id: 1, photo_file_name: "cookies.jpg", photo_content_type: "image/jpeg", photo_file_size: 19571, photo_updated_at: "2018-06-05 23:50:10", description: "Cookies with crisp edges, a rich, buttery, toffee-like flavor, big chocolate chunks.", position: 5},
  {name: "Fire Crackers", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">Graham cracker</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">3.5</span> ground weed</li>\r\n\t<li class=\"list-group-item\">Hazelnut spread</li>\r\n\t<li class=\"list-group-item\">Tin foil</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Place your weed on foil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Preheat your oven in 250&deg; F.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Toast your weed for 10 minutes at 250&deg; F.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Cover graham crackers with hazelnut spread.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong> Remove your weed from oven and sprinkle over hazeulnut spread.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Mix weed into spread and sandwhich graham crackers together.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 7: </strong>Wrap and seal firecracker in foil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 8: </strong>Toast in oven for 15 minutes at 300&deg; F.</li>\r\n</ul>\r\n\r\n<p style=\"text-align: center;\"><em>Do you want to share your recipe? Please send to howtoedibles@gmail.com</em></p>\r\n", suggested_quantity: 1.5, suggested_portion: 6.0, video: "https://www.youtube.com/embed/g-5a12uIE6E", slug: "firecrackers", category_id: 1, photo_file_name: "firecracker-(1).jpg", photo_content_type: "image/jpeg", photo_file_size: 12032, photo_updated_at: "2018-06-05 23:49:57", description: "Easy to make, delicious and extremely potent this recipe is one of the most popular.", position: 6},
  {name: "Infused Olive oil", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">300 ml of olive oil</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">8 </span> ground weed</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Grind your weed fine, you want to make a good surface area of exposure.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Add the ground weed to a canning jar with 300 ml of olive oil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Seal the canning jar very tightly.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Add the canning jar in boiling water using low-medium (240&deg; F - 115&deg; C)&nbsp;heat for over 2 hours.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Put all the jar&#39;s content into a cheesecloth over a metal strainer.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Gather the cheesecloth and squeeze all the remaining liquid out.</li>\r\n</ul>\r\n", suggested_quantity: 2.0, suggested_portion: 20.0, video: "https://www.youtube.com/embed/Szo0ptSKKX4", slug: "infused-olive-oil", category_id: 2, photo_file_name: "oils-(1).jpg", photo_content_type: "image/jpeg", photo_file_size: 13964, photo_updated_at: "2018-06-05 23:49:50", description: "Probably the most versatile medium and a great place to start cooking with cannabis.", position: 9},
  {name: "Pot Brownies", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac12; cup&nbsp;cannabutter - <a class=\"recipe-reference\" href=\"http://www.howtoedibles.com/recipes/cannabutter\" target=\"_blank\">See the recipe</a></li>\r\n\t<li class=\"list-group-item\">1 cup sugar (or any sweetener)</li>\r\n\t<li class=\"list-group-item\">2 eggs</li>\r\n\t<li class=\"list-group-item\">1 teaspoon vanilla extract</li>\r\n\t<li class=\"list-group-item\">&frac14; teaspoon baking powder</li>\r\n\t<li class=\"list-group-item\">⅓ cup cocoa powder</li>\r\n\t<li class=\"list-group-item\">&frac14; teaspoon salt</li>\r\n\t<li class=\"list-group-item\">&frac12; cup of flour (or almond flour)</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Preheat oven to 350&deg; F&nbsp;or 180&deg; C.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Mix the melted butter and sugar until well blended.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Add eggs and vanilla; stir just until blended.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Mix all dry ingredients in a separate bowl.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Stir dry ingredients into the butter/sugar mixture.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Pour into greased 9 x 9 square pan.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 7: </strong>Bake for 20 minutes or until sides just start to pull away from the pan.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 8: </strong>Cool completely before cutting.</li>\r\n</ul>\r\n", suggested_quantity: 3.5, suggested_portion: 30.0, video: "", slug: "pot-brownies", category_id: 1, photo_file_name: "brownies.jpg", photo_content_type: "image/jpeg", photo_file_size: 14497, photo_updated_at: "2018-06-05 23:50:33", description: "Behold! The perfect combination of deliciousness and dopeness", position: 3},
  {name: "Trail Mix", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac14; cup of coconut oil</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">3.5 </span> ground weed</li>\r\n    <li class=\"list-group-item\">Nuts of your preference</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Grind your weed fine, you want to make a good surface area of exposure.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Add the ground weed to a canning jar with &frac14; cup of coconut oil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Seal the canning jar very tightly.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Add the canning jar in boiling water using low-medium (240&deg; F - 115&deg; C) heat for over 2 hours.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Put all the jar&#39;s content into a cheesecloth over a metal strainer.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Gather the cheesecloth and squeeze all the remaining liquid out.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 7: </strong>Mix the coconut oil with some nuts.</li>\r\n</ul>\r\n", suggested_quantity: 2.0, suggested_portion: 10.0, video: "https://www.youtube.com/embed/LDBv5_q-w2E", slug: "trail-mix", category_id: 3, photo_file_name: "nuts2.jpg", photo_content_type: "image/jpeg", photo_file_size: 25522, photo_updated_at: "2019-04-17 00:18:51", description: "A delicious combination of seeds and nuts infused with cannabis oil.", position: 7},
  {name: "Infused Honey", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac12; cup of coconut oil</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">3.5</span> ground weed</li>\r\n\t<li class=\"list-group-item\">300 g honey</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Grind your weed fine, you want to make a good surface area of exposure.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Add the ground weed to a canning jar with &frac12; cup of coconut oil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Seal the canning jar very tightly.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Add the canning jar in boiling water using low-medium heat&nbsp;(240&deg; F - 115&deg; C) for over 2 hours.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Put all the jar&#39;s content into a cheesecloth over a metal strainer.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Gather the cheesecloth and squeeze all the remaining liquid out.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 7: </strong>Add the coconut oil and the honey in the blend</li>\r\n\t<li class=\"list-group-item\"><strong>Step 8: </strong>Put and store all the mixture in a canning jar or mason jar</li>\r\n</ul>\r\n", suggested_quantity: 3.5, suggested_portion: 30.0, video: "https://www.youtube.com/embed/AD3QNMgqgkU", slug: "infused-honey", category_id: 1, photo_file_name: "honey-625_625x421_41461133357.jpg", photo_content_type: "image/jpeg", photo_file_size: 9965, photo_updated_at: "2018-06-05 23:49:19", description: "Infused honey is a great way to get cannabis into your favourite beverages or desserts.", position: 7},
  {name: "Infused Coconut oil", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac12; cup of coconut oil</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">3.5 </span> ground weed</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Add the weed to a canning jar with &frac12; cup of coconut oil.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Seal the canning jar very tightly.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Add the canning jar in boiling water using low-medium (240&deg; F - 115&deg; C) heat for over 2 hours.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Put all the jar&#39;s content into a cheesecloth over a metal strainer.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Gather the cheesecloth and squeeze all the remaining liquid out.</li>\r\n</ul>\r\n", suggested_quantity: 3.5, suggested_portion: 20.0, video: "https://www.youtube.com/embed/x5HrIKDiPH4", slug: "infused-coconut-oil", category_id: 2, photo_file_name: "coconut.jpg", photo_content_type: "image/jpeg", photo_file_size: 6963, photo_updated_at: "2018-06-05 23:50:50", description: "Good for weight loss and can be added to various recipes.", position: 2},
  {name: "Chai", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">Tea Bag</li>\r\n\t<li class=\"list-group-item\">Milk</li>\r\n\t<li class=\"list-group-item\"><span id=\"grams-quantity-recipe\">0.5 </span> ground weed</li>\r\n\t<li class=\"list-group-item\">Ginger</li>\r\n\t<li class=\"list-group-item\">Cardamom</li>\r\n\t<li class=\"list-group-item\">Sugar or any sweetiner</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Before Starting: </strong>Decarb your weed - <a href=\"https://www.youtube.com/watch?v=MYEQaTG0WX8\" target=\"_blank\">Learn how to do</a></li>\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Start boiling some milk in a pot.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Lay out some cheesecloth</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Mash up your ginger and spices</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Put the cannabis with all your mashed spices in a cheesecloth and close it as a tea bag.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Steep the tea bag in the milk for two hours.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Pour the milk in a jug.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 7: </strong>Now, it&#39;s time to prepare your mug, mix the milk with a black tea bag and add some sugar.</li>\r\n</ul>\r\n", suggested_quantity: 1.0, suggested_portion: 4.0, video: "https://www.youtube.com/embed/iLRyCN1XKcI", slug: "chai", category_id: 4, photo_file_name: "chai2-(1).jpg", photo_content_type: "image/jpeg", photo_file_size: 12548, photo_updated_at: "2018-06-05 23:49:30", description: "This warming, potent, cannabis chai tea recipe is a great way to enjoy your tea with an extra kick.", position: 10},
  {name: "Weed Grilled Cheese", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">2 slices bread</li>\r\n\t<li class=\"list-group-item\">2 slices cheddar cheese</li>\r\n\t<li class=\"list-group-item\">2 tsp cannabutter - <a class=\"recipe-reference\" href=\"http://www.howtoedibles.com/recipes/cannabutter\" target=\"_blank\">See the recipe</a></li>\r\n\t<li class=\"list-group-item\">1 tbsp butter</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Evenly spread the regular&nbsp;butter on one side of both pieces of bread. Next, spread the cannabis butter on the other side of the bread.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Place the slice of cheddar cheese on the canna-butter side of the bread. Put the two slices of bread together with the canna-butter side in the middle.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>On medium heat, fry the grilled cheese until the cheese has melted and both sides are golden brown, about 3 minutes per side.</li>\r\n</ul>\r\n\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n", suggested_quantity: 0.5, suggested_portion: 4.0, video: "", slug: "grilled-cheese", category_id: 5, photo_file_name: "grilled-cheese.jpg", photo_content_type: "image/jpeg", photo_file_size: 19064, photo_updated_at: "2020-05-14 00:59:57", description: "Quick and easy cannabis-infused grilled cheese recipe", position: 1},
  {name: "Popcorn", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac14; cup of cannabutter -&nbsp;<span class=\"see_recipe text-right\"><a class=\"recipe-reference\" href=\"http://www.howtoedibles.com/recipes/butter\" target=\"_blank\">See the recipe</a></span></li>\r\n\t<li class=\"list-group-item\">⅓ - ⅔ cups of Popcorn Kernels</li>\r\n\t<li class=\"list-group-item\">Salt to taste</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Heat the butter in a 2 to 3-quart saucepan or pot with a lid set over medium-high heat. Pour in popcorn kernels and sprinkle enough salt to lightly cover the layer of kernels. Remember, you can always add more salt later. Add the butter to the pot and cover with the lid.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>As soon as the kernels start to pop, shake the pan back and forth across the burner constantly until the popping slows down. As soon as the pops are about 2 seconds apart, remove from the heat and pour it into a serving bowl. Taste, and season with additional salt if desired.</li>\r\n</ul>\r\n", suggested_quantity: 2.0, suggested_portion: 10.0, video: "", slug: "popcorn", category_id: 5, photo_file_name: "popcorn.jpg", photo_content_type: "image/jpeg", photo_file_size: 10185, photo_updated_at: "2018-06-05 23:50:26", description: "The perfect salty snack to eat while watching your favorite movies", position: 11},
  {name: "Gummy Bears", ingredients: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\">&frac14; cup of infused coconut oil with <span id=\"grams-quantity-recipe\">3.5 grams</span>&nbsp;weed - <a class=\"recipe-reference\" href=\"http://www.howtoedibles.com/recipes/infused-coconut-oil\" target=\"_blank\">See the recipe</a></li>\r\n\t<li class=\"list-group-item\">3 oz flavored gelatin box</li>\r\n\t<li class=\"list-group-item\">2 tsp or two packs unflavored gelatin</li>\r\n\t<li class=\"list-group-item\">⅔ cup of cold water</li>\r\n\t<li class=\"list-group-item\">&frac12; tsp lecithin</li>\r\n\t<li class=\"list-group-item\">Gummy Bear mold</li>\r\n</ul>\r\n", instructions: "<ul class=\"list-group\">\r\n\t<li class=\"list-group-item\"><strong>Step 1: </strong>Combine the powders, add water and lecithin, stir. Let sit 10-15 min allowing the gelatin to bloom.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 2: </strong>Heat on low heat for five minutes, stir, heat five minutes, stir (repeat until it looks fairly clear).</li>\r\n\t<li class=\"list-group-item\"><strong>Step 3: </strong>Add the infused coconut oil stir in for a minute.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 4: </strong>Transfer to molds and wait 10-15 minutes until gelatin sets.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 5: </strong>Remove from heat and let cool to room temperature.</li>\r\n\t<li class=\"list-group-item\"><strong>Step 6: </strong>Pour it all into a mold, refrigerate overnight. Store in the fridge.\r\n\t<ul>\r\n\t</ul>\r\n\t</li>\r\n</ul>\r\n", suggested_quantity: 5.0, suggested_portion: 50.0, video: "", slug: "gummy-bears", category_id: 1, photo_file_name: "gummybear.jpg", photo_content_type: "image/jpeg", photo_file_size: 10773, photo_updated_at: "2018-06-05 23:50:41", description: "If you're a big gummy bear fan, you're in luck!", position: 4}
])